const allItems = $input.all();
const counts = { 고관련: 0, 검토: 0, 저관련: 0 };
for (const item of allItems) {
  const grade = item.json.관련도등급;
  if (grade === '고관련') counts.고관련++;
  else if (grade === '검토') counts.검토++;
  else counts.저관련++;
}
const total = allItems.length;
const today = new Date().toLocaleDateString('ko-KR', { timeZone: 'Asia/Seoul', year: 'numeric', month: '2-digit', day: '2-digit' });
const summaryText = `📋 <b>정부지원사업 일일 리포트</b>\n📅 ${today}\n\n🔥 긴급검토: ${counts.고관련}건\n🧐 검토권장: ${counts.검토}건\n⚪ 저관련: ${counts.저관련}건\n\n📊 총 분석: ${total}건`;
return [{ json: { summaryText, counts, total, today } }];

// 공고 원문 HTML 파싱 + 이전 공고 데이터 병합 + 첨부파일 URL 추출
// HTTP Request의 continueOnFail=true이므로 크롤링 실패 시에도 동작

const crawlResult = $json;

// 이전 노드(회사정보 통합1)에서 공고 원본 데이터 가져오기
let originalData = {};
try {
  originalData = $('회사정보 통합1').item.json;
} catch (e) {
  originalData = {};
}

// 크롤링된 HTML에서 텍스트 추출
let rawHtml = '';
let crawlSuccess = false;

try {
  rawHtml = crawlResult.data || crawlResult.body || '';
  if (typeof rawHtml === 'object') rawHtml = JSON.stringify(rawHtml);
  crawlSuccess = rawHtml.length > 100;
} catch (e) {
  rawHtml = '';
  crawlSuccess = false;
}

// === 첨부파일 URL 추출 ===
const attachments = [];
let hasHwpx = false;

if (crawlSuccess) {
  // 기업마당/보조금24/K-Startup 공통 패턴
  const attachRegex = /href=["']([^"']*(?:getImageFile|FileDown|download|atchFileId|fileDown|downloadFile|getFile)[^"']*)/gi;
  let match;
  while ((match = attachRegex.exec(rawHtml)) !== null) {
    let url = match[1];
    // 상대 URL → 절대 URL 변환
    if (url.startsWith('/')) {
      try {
        const link = originalData['신청Link'] || 'https://www.bizinfo.go.kr';
        const baseUrl = link.match(/^https?:\/\/[^/]+/);
        if (baseUrl) url = baseUrl[0] + url;
      } catch (e) {}
    }
    if (!attachments.includes(url)) attachments.push(url);
  }

  // .hwp/.hwpx 직접 링크 패턴
  const hwpLinkRegex = /href=["']([^"']*\.hwp[x]?(?:\?[^"']*)?)/gi;
  while ((match = hwpLinkRegex.exec(rawHtml)) !== null) {
    let url = match[1];
    if (url.startsWith('/')) {
      try {
        const link = originalData['신청Link'] || 'https://www.bizinfo.go.kr';
        const baseUrl = link.match(/^https?:\/\/[^/]+/);
        if (baseUrl) url = baseUrl[0] + url;
      } catch (e) {}
    }
    if (!attachments.includes(url)) attachments.push(url);
  }

  // hwpx 파일 존재 여부 확인
  hasHwpx = attachments.some(u => /\.hwpx/i.test(u) || u.includes('atchFileId'));
}

let extractedText = '';
if (crawlSuccess) {
  extractedText = rawHtml
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s{2,}/g, ' ')
    .trim();

  // 2,000자 제한 (Phase 8: 3,000→2,000 축소 — Gemini 입력 토큰 절약)
  if (extractedText.length > 2000) {
    extractedText = extractedText.substring(0, 2000) + '...(생략)';
  }
}

const finalText = extractedText || '원문 크롤링 실패 - API 요약 정보만 사용';
const didCrawl = !!(extractedText && extractedText !== '원문 크롤링 실패 - API 요약 정보만 사용');

return {
  json: {
    ...originalData,
    원문내용: finalText,
    원문_크롤링여부: didCrawl,
    첨부파일URL: attachments.length > 0 ? JSON.stringify(attachments) : '',
    '첨부파일_HWPX여부': hasHwpx,
  }
};

// 프레스코21 최적화 키워드 점수화 v5.2 (2026-03-19)
// 변경: 실 데이터 기반 + 지역 prefix 강제 필터
// 변경: 고용/절세/서울 키워드 추가 (Phase 8 Quick Win)

const HIGH_TITLE = 20, HIGH_BODY = 10;
const MID_TITLE  = 10, MID_BODY  = 5;
const PENALTY    = -15;

// HIGH (공고명 +20점, 내용 +10점) — 핵심 자격·관심사
const HIGH_KW = [
  // 기업 규모/유형
  '소상공인', '소기업', '중소기업', '자영업', '1인기업',
  // 여성기업 (인증 보유 → 자격 있음)
  '여성기업', '여성창업', '여성CEO',
  // 핵심 업종
  '화훼', '꽃', '플라워', '원예', '공예', '공예품', '기념품', '답례품', '웨딩',
  // 전자상거래·온라인 (기존 + 추가)
  '전자상거래', '온라인', '쇼핑몰', 'e커머스', '이커머스', '자사몰',
  '통신판매', '라이브커머스', '오픈마켓', '스마트스토어', '온라인판매', '온라인쇼핑',
  // 마케팅·판로 (최우선 관심)
  '판로', '마케팅', 'SNS', '광고', '홍보', '콘텐츠', '브랜드',
  // 유통 (MID→HIGH: 온라인 쇼핑몰 핵심 연관)
  '유통', '유통채널',
  // 디지털전환
  '디지털', 'IT', '스마트',
  // 역량강화·교육
  '교육', '훈련', '역량강화', '컨설팅',
  // 지역 (송파구 가락동)
  '서울', '송파',
  // 고용지원 (직원 유지·안정 관련)
  '일자리안정자금', '두루누리', '사회보험료', '고용지원금', '고용안정', '워라밸', '근로환경',
  // 절세·세제혜택
  '세액감면', '조세지원', '세제혜택', '절세', '세무', '부가세', '법인세',
  // 서울 지역 지원기관
  '서울형', 'SBA', '서울산업진흥원', '송파구', '강남구', '서울시',
];

// MID (공고명 +10점, 내용 +5점) — 보조 관심사
const MID_KW = [
  // 수출 (언젠간 관심, 지금은 아님)
  '수출', '해외진출', '글로벌',
  // 창업 (26년 업력 → 창업 전용 공고 대부분 해당 없음)
  '창업', '스타트업',
  // 기타 관련
  '플랫폼', '물류',
  // 사람 특성 (청년 직원 2~4명 있음)
  '청년',
  // 지역
  '수도권',
  // 사회경제
  '사회적기업',
  // 고용 보조 (교육·인력 양성)
  '직업훈련', '직무능력', '인력양성',
  // 경영안정
  '경영안정', '자금지원',
];

// LOW (출현시 -15점) — 자격 없거나 무관 업종
const LOW_KW = [
  // 완전 무관 업종
  '농업', '수산', '어업', '임업', '광업',
  '건설', '토목', '건축',
  '의료', '병원', '제약', '바이오',
  '자동차', '중장비', '조선',
  // R&D (꽃/공예 도소매는 기술개발 공고 해당 없음)
  'R&D', '연구개발', '기술개발',
  // 벤처 (벤처기업 인증 없음)
  '벤처',
  // 신규 고용/채용 (당분간 채용 계획 없음)
  '신규채용', '신규고용', '채용보조금',
  // 지역 전용 (서울 외)
  '부산', '대구', '인천', '광주', '대전', '울산', '세종',
  '강원', '충북', '충남', '전북', '전남', '경북', '경남', '제주',
  // 대기업/중견기업 전용
  '중견기업', '대기업', '상장사',
  // 제조업 전용 (도소매업과 무관)
  '제조업', '제조', '생산', '스마트공장', '뿌리기업', '뿌리산업',
  // 특수 업종
  '문화예술', '관광', '영화', '게임', '방송',
];

const results = [];
for (const item of $input.all()) {

// === 지역 공고 강제 필터 (v5.2) ===
// [경기], [부산] 등 서울/전국 외 지역 prefix → 강제 0점
const titleRaw = item.json['지원사업이름'] || '';
const regionMatch = titleRaw.match(/^\[([^\]]+)\]/);
if (regionMatch) {
  const region = regionMatch[1];
  const allowedRegions = ['서울', '전국'];
  if (!allowedRegions.some(r => region.includes(r))) {
    results.push({ json: { ...item.json, kwScore: 0 } });
    continue;
  }
}
  const title = (item.json['지원사업이름'] || '') + ' ' + (item.json['지원대상'] || '');
  const body  = (item.json['사업개요'] || '') + ' ' + (item.json['지원분야'] || '');

  let score = 0;
  HIGH_KW.forEach(kw => {
    if (title.includes(kw)) score += HIGH_TITLE;
    else if (body.includes(kw)) score += HIGH_BODY;
  });
  MID_KW.forEach(kw => {
    if (title.includes(kw)) score += MID_TITLE;
    else if (body.includes(kw)) score += MID_BODY;
  });
  LOW_KW.forEach(kw => {
    if (title.includes(kw) || body.includes(kw)) score += PENALTY;
  });

  results.push({ json: { ...item.json, kwScore: Math.max(0, score) } });
}
return results;

// 키워드 점수 기준 상위 30건 선별 - Gemini 413 오류 방지
const items = $input.all();
const sorted = [...items].sort((a, b) => (b.json.kwScore || 0) - (a.json.kwScore || 0));
const TOP_N = 30;
const top = sorted.slice(0, TOP_N);
// 로그: 점수 분포 확인용
const totalCount = items.length;
const selectedCount = top.length;
const scores = top.map(i => i.json.kwScore || 0);
const minScore = scores.length > 0 ? Math.min(...scores) : 0;
const maxScore = scores.length > 0 ? Math.max(...scores) : 0;
console.log('전체 ' + totalCount + '건 중 상위 ' + selectedCount + '건 선별 (점수 범위: ' + minScore + '~' + maxScore + ')');
return top.map(item => ({ json: item.json }));

// Stage1 데이터 준비: 원문 파싱 결과를 배치 처리용으로 변환 (v1)
const allItems = $input.all();

// 공고 데이터만 추출 (공고ID가 있는 것)
const announcements = allItems.filter(item => item.json.공고ID && item.json.지원사업이름);

if (announcements.length === 0) {
  return [{ json: { _noItems: true } }];
}

// 각 공고를 개별 아이템으로 반환 (SplitInBatches에서 5건씩 처리)
return announcements.map(item => ({
  json: {
    공고ID: item.json.공고ID,
    지원사업이름: item.json.지원사업이름,
    소관기관: (item.json.소관기관 || '').substring(0, 30),
    지원대상: (item.json.지원대상 || '').substring(0, 100),
    지원분야: (item.json.지원분야 || '').substring(0, 50),
    사업개요: (item.json.사업개요 || '').substring(0, 150),
    지역: item.json.지역 || '전국',
    원문내용: (item.json.원문내용 || '').substring(0, 2000),
    원문_크롤링여부: item.json.원문_크롤링여부 || false,
    신청Link: item.json.신청Link || '',
    마감일: item.json.마감일 || '',
    수집출처: item.json.수집출처 || '',
    첨부파일URL: item.json.첨부파일URL || '',
    '첨부파일_HWPX여부': item.json['첨부파일_HWPX여부'] || false,
    kwScore: item.json.kwScore || 0,
  }
}));

// Stage1: 공고 원문 구조화 프롬프트 생성 (배치 5건)
const batchItems = $input.all();

const batchList = batchItems.map(item => ({
  idx: item.json.공고ID,
  사업명: item.json.지원사업이름,
  원문: (item.json.원문내용 || item.json.사업개요 || '정보 없음').substring(0, 2000),
}));

const systemPrompt = '당신은 정부지원사업 공고 원문 파서입니다. 반드시 순수 JSON 배열만 반환하고, 마크다운 코드블록 없이 [ 로 시작하여 ] 로 끝나야 합니다.';

const userPrompt = '아래 ' + batchList.length + '개 공고의 원문에서 핵심 정보를 JSON으로 구조화하세요.\n\n' +
  batchList.map((item, i) => '[공고 ' + (i+1) + ']\n- 사업명: ' + item.사업명 + '\n- 원문: ' + item.원문).join('\n\n') +
  '\n\n출력: [{"idx":"공고ID","사업목적":"","지원대상":"","지원내용":"","신청기간":"","필요서류":[],"신청방법":"","제한사항":"","첨부서식목록":[],"파싱품질":"상/중/하"},...]\n\n순수 JSON 배열만 출력하세요.';

const fullPrompt = systemPrompt + '\n\n' + userPrompt;

// 페이로드 크기 체크 (50KB 초과 시 원문 축소)
let payload = JSON.stringify({
  contents: [{ role: 'user', parts: [{ text: fullPrompt }] }],
  generationConfig: { maxOutputTokens: 8192, thinkingConfig: { thinkingBudget: 0 } }
});

if (payload.length > 50000) {
  // 원문을 1000자로 재절단
  const shortList = batchItems.map(item => ({
    idx: item.json.공고ID,
    사업명: item.json.지원사업이름,
    원문: (item.json.원문내용 || item.json.사업개요 || '정보 없음').substring(0, 1000),
  }));
  const shortPrompt = systemPrompt + '\n\n' +
    '아래 ' + shortList.length + '개 공고의 원문에서 핵심 정보를 JSON으로 구조화하세요.\n\n' +
    shortList.map((item, i) => '[공고 ' + (i+1) + ']\n- 사업명: ' + item.사업명 + '\n- 원문: ' + item.원문).join('\n\n') +
    '\n\n출력: [{"idx":"공고ID","사업목적":"","지원대상":"","지원내용":"","신청기간":"","필요서류":[],"신청방법":"","제한사항":"","첨부서식목록":[],"파싱품질":"상/중/하"},...]\n\n순수 JSON 배열만 출력하세요.';
  payload = JSON.stringify({
    contents: [{ role: 'user', parts: [{ text: shortPrompt }] }],
    generationConfig: { maxOutputTokens: 8192, thinkingConfig: { thinkingBudget: 0 } }
  });
}

return [{ json: { requestBody: payload, _batchIds: batchItems.map(i => i.json.공고ID) } }];

// Stage1 응답 파싱: Gemini 구조화 결과를 원본 데이터에 병합
const response = $input.first();
const batchIds = response.json._batchIds || [];

// Gemini 응답에서 텍스트 추출
function extractText(r) {
  if (!r) return '';
  const j = r.json || r;
  if (j.candidates && j.candidates[0] && j.candidates[0].content) {
    return j.candidates[0].content.parts[0].text || '';
  }
  if (j.text) return j.text;
  const str = JSON.stringify(j);
  const m = str.match(/"text"\s*:\s*"([\s\S]*?)"/);
  return m ? m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : '';
}

const text = extractText(response);

// JSON 배열 파싱
let parsed = [];
try {
  const codeBlockMatch = text.match(/```(?:json)?\s*(\[[\s\S]*?\])\s*```/);
  const jsonStr = codeBlockMatch ? codeBlockMatch[1] : (text.match(/\[[\s\S]*\]/) || ['[]'])[0];
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = [];
}

// Stage1 배치 분할 노드에서 원본 데이터 가져오기
const batchItems = $('Stage1 배치 (5건)').all();

// 구조화 결과를 원본에 병합
const structMap = {};
for (const item of parsed) {
  structMap[String(item.idx)] = item;
}

return batchItems.map(orig => {
  const s = structMap[String(orig.json.공고ID)] || {};
  return {
    json: {
      ...orig.json,
      _s1_사업목적: s.사업목적 || '',
      _s1_지원대상: s.지원대상 || '',
      _s1_지원내용: s.지원내용 || '',
      _s1_신청기간: s.신청기간 || '',
      _s1_필요서류: JSON.stringify(s.필요서류 || []),
      _s1_신청방법: s.신청방법 || '',
      _s1_제한사항: s.제한사항 || '',
      _s1_첨부서식목록: JSON.stringify(s.첨부서식목록 || []),
      _s1_파싱품질: s.파싱품질 || '하',
    }
  };
});

// Stage1 결과 집계: 모든 배치의 구조화 결과를 하나로 모음
// SplitInBatches 완료 출력(output 0)으로부터 수집
const allItems = $input.all();
// 이미 모든 배치 결과가 집계되어 들어옴
return allItems.map(item => ({ json: item.json }));

// Stage2 v3: 자격매칭 + 종합평가 프롬프트 생성 (배치 5건)
// NocoDB 회사 프로파일 동적 로드 (43개 필드)
let profile = {};
try {
  const companyItems = $('회사정보 조회').all();
  if (companyItems.length > 0) {
    const raw = companyItems[0].json;
    if (raw.list && raw.list.length > 0) profile = raw.list[0];
    else profile = raw;
  }
} catch (e) {}

const g = (k, d) => profile[k] || d;

const batchItems = $input.all();
const batchList = batchItems.map(item => ({
  id: item.json.공고ID,
  제목: item.json.지원사업이름,
  사업목적: item.json._s1_사업목적 || '',
  지원대상_구조화: item.json._s1_지원대상 || item.json.지원대상 || '',
  지원내용: item.json._s1_지원내용 || '',
  신청기간: item.json._s1_신청기간 || '',
  제한사항: item.json._s1_제한사항 || '',
  지역: item.json.지역 || '전국',
}));

// 어필포인트 JSON 파싱 → 구조화 텍스트 변환
let appealText = '';
try {
  const ap = JSON.parse(g('어필포인트_JSON', '{}'));
  const lines = Object.entries(ap).map(([k, v]) => '- ' + k.replace(/_/g,' ') + ': ' + v['어필1'] + ' / ' + v['핵심수치']);
  appealText = lines.join('\n');
} catch (e) { appealText = '(미등록)'; }

const systemPrompt = '당신은 Pressco21의 정부지원사업 전략 분석가입니다. 반드시 순수 JSON 배열만 반환하고, 마크다운 코드블록 없이 [ 로 시작하여 ] 로 끝나야 합니다.';

const companyBlock = '[회사 현황]\n' +
  '회사명: ' + g('회사명','프레스코21') + ' / 사업자등록번호: ' + g('사업자등록번호','215-05-52221') + '\n' +
  '업종: ' + g('업종','꽃·공예 도소매업') + '\n' +
  '업태: ' + g('업태','도소매, 제조, 전자상거래') + ' / 종목: ' + g('종목','꽃, 전자상거래 소매업') + '\n' +
  '업종코드: ' + g('업종코드','525101') + ' (전자상거래 소매업)\n' +
  '대표: ' + g('대표자','이진선 (여성, 만 65세)') + '\n' +
  '창업: ' + g('업력','1999.12 (26년)') + '\n' +
  '소재지: ' + g('소재지','서울 송파구') + '\n' +
  '직원: ' + g('직원','8명') + '\n' +
  '연매출: ' + g('연매출','11.6억') + ' / 매출총이익률: ' + g('매출총이익률','59.3') + '%\n' +
  '부채비율: ' + g('부채비율','27.2') + '% (매우 건전)\n' +
  '자가부동산: 221평 (토지+건물 15.67억 매입)\n\n' +
  '[보유 인증/실적]\n' +
  '- 인증: ' + g('보유인증','여성기업인증, 소기업확인서') + '\n' +
  '- 특허: ' + g('보유특허_건수','4') + '건 (실용신안 3건 + 특허 1건)\n' +
  '- 국무총리 표창 (2010), 모범여성기업인 (2005)\n' +
  '- 공공납품: ' + g('공공납품_실적','16곳') + '\n' +
  '- 대기업: ' + g('대기업_납품','LG생활건강, 삼성화재') + '\n' +
  '- 수출: ' + g('수출_규모','약 500만원') + ', 50여개국 국제교류\n' +
  '- 사회공헌: ' + g('사회공헌_실적','장애인복지관 교육, 기부 4587만') + '\n' +
  '- IT자동화: n8n 14개 WF + AI챗봇 자체 구축\n' +
  '- 콘텐츠: 유튜브 2160구독/467영상, MBC/KBS/SBS 출연\n' +
  '- 정부지원 수혜이력: ' + g('정부지원_수혜이력','없음 (첫 신청)') + '\n' +
  '- 판매채널: ' + g('판매채널','자사몰, 스마트스토어, 쿠팡, 11번가') + '\n' +
  '- 관심 분야: ' + g('최우선관심','마케팅·판로 확대') + '\n' +
  '- 추가 관심: ' + g('추가관심','디지털전환, 역량강화, 수출');

const typeBlock = '[공고 유형별 자격 판단 기준]\n' +
  '1. 여성기업 지원: 인증 보유 + 26년 여성 대표 → 매우 높은 적합도 (85점+)\n' +
  '2. 소상공인 마케팅/판로/전자상거래: 자사몰+오픈마켓 운영 → 높은 적합도 (75점+)\n' +
  '3. 디지털전환: n8n+AI 자동화 자체 구축 실적 → 높은 적합도 (75점+)\n' +
  '4. 고용지원/워라밸: 8명 안정고용, 출산휴가 운영 → 높은 적합도 (70점+)\n' +
  '5. 콘텐츠/마케팅 지원: YT 467영상 + 방송출연 → 높은 적합도 (70점+)\n' +
  '6. 컨설팅/멘토링: 26년 업력 + 10000명 강사양성 → 중간 적합도 (60점+)\n' +
  '7. 수출/해외진출: 소규모 수출 + 국제교류 → 중간 적합도 (50점+)\n' +
  '8. R&D/기술개발: 특허 4건 있으나 주업종 아님 → 조건부 (40~60점)\n' +
  '9. 제조업 전용: 업태에 제조 포함되나 주매출 도소매 → 신중 판단 (30~50점)\n' +
  '10. 창업초기 전용 (3년이내): 업력 26년 → 자격 없음 (0점)';

const disqualifyBlock = '[절대 부적합 → 0~10점]\n' +
  '- 창업 3년 이내 조건\n' +
  '- 농업/수산/광업/건설/의료/자동차 전용\n' +
  '- 비서울 지역 전용 (경기/부산/대구 등)\n' +
  '- 중견기업/대기업 대상\n' +
  '- 스마트공장/제조 전용\n' +
  '- 신규채용 필수 조건 (채용 계획 없음)';

const bonusBlock = '[우대 조건 → 보너스 점수 고려]\n' +
  '- 여성기업 키워드 포함 → +15점\n' +
  '- 소상공인 + 마케팅/판로 → +10점\n' +
  '- 전자상거래 + 디지털전환 → +10점\n' +
  '- 서울/송파 지역 한정 → +5점\n' +
  '- 정부지원 첫 신청 우대 명시 → +5점';

const userPrompt = companyBlock + '\n\n' + typeBlock + '\n\n' + disqualifyBlock + '\n\n' + bonusBlock +
  '\n\n[어필 포인트 요약]\n' + appealText +
  '\n\n[공고 ' + batchList.length + '건 - Stage1 구조화 결과]\n' + JSON.stringify(batchList) +
  '\n\n각 공고에 대해 아래 JSON 배열 반환:\n' +
  '[{"id":"공고ID","관련도점수":정수0~100,"관련도등급":"고관련/검토/저관련","신청자격_충족여부":"충족/부분충족/미충족",' +
  '"불일치항목":[],"적합이유":"","신청팁":"","카테고리":"","신청난이도":"상/중/하",' +
  '"예상지원규모":"","신청성공가능성":"높음/보통/낮음","추천이유_상세":"","핵심신청자격":""}]\n\n' +
  '점수: 고관련=70+, 검토=40~69, 저관련=0~39. 자격 불일치는 반드시 39점 이하.';

const fullPrompt = systemPrompt + '\n\n' + userPrompt;

const payload = JSON.stringify({
  contents: [{ role: 'user', parts: [{ text: fullPrompt }] }],
  generationConfig: { maxOutputTokens: 8192, thinkingConfig: { thinkingBudget: 0 } }
});

return [{ json: { requestBody: payload, _batchIds: batchItems.map(i => i.json.공고ID) } }];

// Stage2 응답 파싱: Gemini 평가 결과를 원본 데이터에 병합
const response = $input.first();

function extractText(r) {
  if (!r) return '';
  const j = r.json || r;
  if (j.candidates && j.candidates[0] && j.candidates[0].content) {
    return j.candidates[0].content.parts[0].text || '';
  }
  if (j.text) return j.text;
  const str = JSON.stringify(j);
  const m = str.match(/"text"\s*:\s*"([\s\S]*?)"/);
  return m ? m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : '';
}

const text = extractText(response);

let parsed = [];
try {
  const codeBlockMatch = text.match(/```(?:json)?\s*(\[[\s\S]*?\])\s*```/);
  const jsonStr = codeBlockMatch ? codeBlockMatch[1] : (text.match(/\[[\s\S]*\]/) || ['[]'])[0];
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = [];
}

// Stage2 배치에서 원본 데이터 가져오기
const batchItems = $('Stage2 배치 (5건)').all();

const scoreMap = {};
for (const item of parsed) {
  scoreMap[String(item.id)] = item;
}

return batchItems.map(orig => {
  const sd = scoreMap[String(orig.json.공고ID)] || {};
  const score = Number(sd.관련도점수 ?? 0);
  const grade = score >= 70 ? '고관련' : score >= 30 ? '검토' : '저관련';
  return {
    json: {
      ...orig.json,
      관련도점수: score,
      관련도등급: grade,
      관련도이유: sd.적합이유 || '',
      적합이유: sd.적합이유 || '',
      신청팁: sd.신청팁 || '',
      카테고리: sd.카테고리 || '',
      신청난이도: sd.신청난이도 || '',
      예상지원규모: sd.예상지원규모 || '',
      필요서류_예측: orig.json._s1_필요서류 || '[]',
      추천이유_상세: sd.추천이유_상세 || '',
      신청자격_충족여부: sd.신청자격_충족여부 || '',
      신청성공가능성: sd.신청성공가능성 || '',
      핵심신청자격: sd.핵심신청자격 || '',
    }
  };
});

// Stage2 결과 집계: 모든 배치의 평가 결과를 최종 출력
const allItems = $input.all();
return allItems.map(item => ({ json: item.json }));

