// 기업마당 API 응답 정규화
// 실제 구조: { jsonArray: [ {pblancId, pblancNm, ...}, {...} ] }

const items = $input.first().json;
const normalized = [];

try {
  // jsonArray가 배열로 직접 들어옴 (item 없음)
  const data = items.jsonArray || [];
  const dataArray = Array.isArray(data) ? data : [data];

  console.log(`기업마당 데이터 수: ${dataArray.length}`);

  for (const item of dataArray) {
    // pblancId 필드 확인
    if (!item.pblancId) {
      console.log('pblancId 없음:', Object.keys(item).slice(0, 5));
      continue;
    }

    // 날짜 파싱: "20260107 ~ 20260205" 형식
    let startDate = null;
    let endDate = null;
    if (item.reqstBeginEndDe) {
      const dates = item.reqstBeginEndDe.split('~').map(d => d.trim());
      if (dates[0] && dates[0].length >= 8) {
        const d = dates[0].replace(/[^0-9]/g, '').slice(0, 8);
        startDate = `${d.slice(0,4)}-${d.slice(4,6)}-${d.slice(6,8)}`;
      }
      if (dates[1] && dates[1].length >= 8) {
        const d = dates[1].replace(/[^0-9]/g, '').slice(0, 8);
        endDate = `${d.slice(0,4)}-${d.slice(4,6)}-${d.slice(6,8)}`;
      }
    }

    // 지역 추출 (hashTags에서)
    const regions = ['서울','부산','대구','인천','광주','대전','울산','세종','경기','강원','충북','충남','전북','전남','경북','경남','제주'];
    const hashTags = item.hashTags || item.hashtags || '';
    const region = hashTags.split(',').find(t => regions.includes(t.trim())) || '전국';

    // ✅ 게시일시_raw: creatPnttm(등록/게시일시 후보)
    const postedRaw = item.creatPnttm || item.createdDt || item.creatDt || null;

    normalized.push({
      json: {
        공고ID: `BIZINFO_${item.pblancId}`,
        지원사업이름: item.pblancNm || '',
        소관기관: item.jrsdInsttNm || '',
        수행기관: item.excInsttNm || '',
        지원분야: item.pldirSportRealmLclasCodeNm || '',
        지원대상: item.trgetNm || '',
        사업개요: item.bsnsSumryCn || '',
        지역: region,
        신청시작일: startDate,
        마감일: endDate,
        신청방법: item.reqstMthPapersCn || '',
        신청Link: item.pblancUrl ? (item.pblancUrl.startsWith('http') ? item.pblancUrl : 'https://www.bizinfo.go.kr' + item.pblancUrl) : '',
        지원금액: '',
        수집출처: '기업마당',

        게시일시_raw: postedRaw,
        게시일시_source: postedRaw ? 'creatPnttm' : ''
      }
    });
  }

  console.log(`기업마당 정규화 완료: ${normalized.length}건`);

} catch (e) {
  console.log('기업마당 파싱 오류:', e.message);
}

return normalized.length > 0 ? normalized : [{ json: { _empty: true, source: '기업마당', error: '데이터 없음' } }];

// K-Startup API 응답 정규화
// 실제 구조: { data: [ {pbanc_sn, biz_pbanc_nm, pbanc_rcpt_bgng_dt, ...} ] }
// 필드명이 스네이크케이스임

const items = $input.first().json;
const normalized = [];

try {
  // data 배열로 직접 들어옴
  const data = items.data || items.response?.body?.items?.item || [];
  const dataArray = Array.isArray(data) ? data : [data];

  console.log(`K-Startup 데이터 수: ${dataArray.length}`);
  if (dataArray[0]) {
    console.log('K-Startup 샘플 필드:', Object.keys(dataArray[0]).slice(0, 10));
  }

  for (const item of dataArray) {
    // pbanc_sn 또는 id 필드 확인
    const id = item.pbanc_sn || item.id || item.pbancId;
    if (!id) {
      continue;
    }

    // 날짜 파싱: "20260108" 형식
    let startDate = null;
    let endDate = null;

    const startRaw = item.pbanc_rcpt_bgng_dt || item.reqstBeginDe || '';
    const endRaw = item.pbanc_rcpt_end_dt || item.reqstEndDe || '';

    if (startRaw && String(startRaw).length >= 8) {
      const d = String(startRaw).replace(/[^0-9]/g, '').slice(0, 8);
      startDate = `${d.slice(0,4)}-${d.slice(4,6)}-${d.slice(6,8)}`;
    }
    if (endRaw && String(endRaw).length >= 8) {
      const d = String(endRaw).replace(/[^0-9]/g, '').slice(0, 8);
      endDate = `${d.slice(0,4)}-${d.slice(4,6)}-${d.slice(6,8)}`;
    }

    // ✅ 게시일시_raw 후보:
    // - 만약 API가 별도의 등록/게시일 필드를 제공하면 그것을 우선
    // - 없으면 현실적으로 pbanc_rcpt_bgng_dt(접수시작일)를 fallback으로 사용
    const postedRaw =
      item.pbanc_rgst_dt ||
      item.pbanc_reg_dt ||
      item.reg_dt ||
      item.created_dt ||
      item.creat_dt ||
      item.pbanc_rcpt_bgng_dt ||
      null;

    const postedSource =
      item.pbanc_rgst_dt ? 'pbanc_rgst_dt' :
      item.pbanc_reg_dt ? 'pbanc_reg_dt' :
      item.reg_dt ? 'reg_dt' :
      item.created_dt ? 'created_dt' :
      item.creat_dt ? 'creat_dt' :
      item.pbanc_rcpt_bgng_dt ? 'pbanc_rcpt_bgng_dt' :
      '';

    normalized.push({
      json: {
        공고ID: `KSTARTUP_${id}`,
        지원사업이름: item.biz_pbanc_nm || item.pbancNm || '',
        소관기관: item.biz_prch_dprt_nm || item.mngtInsttNm || '',
        수행기관: item.sprv_inst || '',
        지원분야: item.supt_biz_clsfc || item.sportFldNm || '',
        지원대상: item.biz_trgt_age || item.trgetCn || '',
        사업개요: item.pbanc_ctnt || item.bsnsSumryCn || '',
        지역: item.supt_regin || item.sportRgnNm || '전국',
        신청시작일: startDate,
        마감일: endDate,
        신청방법: item.aply_mthd_etc_istc || '',
        신청Link: item.detl_pg_url || item.pbancUrl || '',
        지원금액: '',
        수집출처: 'K-Startup',

        게시일시_raw: postedRaw,
        게시일시_source: postedSource
      }
    });
  }

  console.log(`K-Startup 정규화 완료: ${normalized.length}건`);

} catch (e) {
  console.log('K-Startup 파싱 오류:', e.message);
}

return normalized.length > 0 ? normalized : [{ json: { _empty: true, source: 'K-Startup', error: '데이터 없음' } }];

// 보조금24 API 응답 정규화 (게시일 기준 = 수정일시 우선)
// - '등록일시', '수정일시' 둘 다 존재하는 경우가 많으므로, "어제~지금" 기준은 수정일시로 운영
// - 수정일시가 없으면 등록일시로 fallback

const items = $input.first().json;
const normalized = [];

try {
  const data = items.data || items.response?.body?.items?.item || [];
  const dataArray = Array.isArray(data) ? data : [data];

  console.log(`보조금24 데이터 수: ${dataArray.length}`);

  for (const item of dataArray) {
    const id = item['서비스ID'] || item.servId || item.id;
    if (!id) continue;

    const createdRaw =
      item['등록일시'] ||
      item['등록일자'] ||
      item['등록일'] ||
      null;

    const updatedRaw =
      item['수정일시'] ||
      item['수정일자'] ||
      item['수정일'] ||
      null;

    // ✅ 게시일시_raw = 수정일시 우선
    const postedRaw = updatedRaw || createdRaw || null;
    const postedSource = updatedRaw ? '수정일시' : createdRaw ? '등록일시' : '';

    normalized.push({
      json: {
        공고ID: `SUBSIDY24_${id}`,
        지원사업이름: item['서비스명'] || item.servNm || '',
        소관기관: item['소관기관명'] || item.jurMnofNm || '',
        수행기관: item['소관기관유형'] || item.jurOrgNm || '',
        지원분야: item['서비스분야'] || item.svcCtgryNm || '',
        지원대상: item['지원대상'] || item.trgterIndvdlArray || '',
        사업개요: item['서비스목적요약'] || item.servDgst || '',
        지역: item['사용자구분'] || item.ctpvNm || '전국',
        신청시작일: null,
        마감일: null,
        신청방법: item['신청방법'] || item.aplyMtdNm || '',
        신청Link: item['상세조회URL'] || item.servDtlLink || '',
        지원금액: item['지원내용'] || item.sprtCycNm || '',
        수집출처: '보조금24',

        // ✅ 게시/기준값
        게시일시_raw: postedRaw,
        게시일시_source: postedSource,

        // ✅ 업데이트 감지/디버깅용 원천 값
        수정일시_raw: updatedRaw,
        등록일시_raw: createdRaw
      }
    });
  }

  console.log(`보조금24 정규화 완료: ${normalized.length}건`);
} catch (e) {
  console.log('보조금24 파싱 오류:', e.message);
}

return normalized.length > 0
  ? normalized
  : [{ json: { _empty: true, source: '보조금24', error: '데이터 없음' } }];

// NocoDB 지원 - 기존 공고ID 조회가 NocoDB HTTP 응답(list 배열)으로 옴
// _fromNocoDB: true 로 기존 레코드 식별

const rawItems = $input.all();

// NocoDB list 응답 확장: {list: [...]} → 개별 아이템
const allItems = [];
for (const rawItem of rawItems) {
  const j = rawItem.json;
  if (j && j.list && Array.isArray(j.list)) {
    // NocoDB HTTP GET 응답 - list 배열 확장
    for (const record of j.list) {
      allItems.push({ json: { _fromNocoDB: true, 공고ID: record.공고ID, Id: record.Id } });
    }
  } else if (j && j._fromNocoDB) {
    allItems.push(rawItem);
  } else {
    allItems.push(rawItem);
  }
}

const KST_OFFSET_MS = 9 * 60 * 60 * 1000;
const nowUtcMs = Date.now();
const nowKst = new Date(nowUtcMs + KST_OFFSET_MS);
const y = nowKst.getUTCFullYear();
const m = nowKst.getUTCMonth();
const d = nowKst.getUTCDate();

const LOOKBACK_DAYS_DEFAULT = 14;  // 초기 적재용 (이후 7로 변경)
const LOOKBACK_DAYS_SUBSIDY24 = 30;
const FORCE_FULL_SYNC_ALL = false;
const FORCE_FULL_SYNC_SUBSIDY24 = false;

const startUtcMsDefault = Date.UTC(y, m, d - LOOKBACK_DAYS_DEFAULT, 0, 0, 0) - KST_OFFSET_MS;
const startUtcMsSubsidy24 = Date.UTC(y, m, d - LOOKBACK_DAYS_SUBSIDY24, 0, 0, 0) - KST_OFFSET_MS;
const endUtcMs = nowUtcMs;

function parseToUtcMs(raw) {
  if (raw === null || raw === undefined) return null;
  const s0 = String(raw).trim();
  if (!s0) return null;
  if (/Z$|GMT|[+-]\d{2}:?\d{2}$/.test(s0)) {
    const t = Date.parse(s0);
    return Number.isFinite(t) ? t : null;
  }
  const m1 = s0.match(/^(\d{4})-(\d{2})-(\d{2})(?:[T\s]+(\d{2}):(\d{2})(?::(\d{2}))?(?:\.\d+)?)?$/);
  if (m1) {
    return Date.UTC(+m1[1],+m1[2]-1,+m1[3],+(m1[4]||0),+(m1[5]||0),+(m1[6]||0)) - KST_OFFSET_MS;
  }
  // 14자리: YYYYMMDDHHmmss (보조금24 등)
  const m14 = s0.match(/^(\d{4})(\d{2})(\d{2})(\d{2})(\d{2})(\d{2})$/);
  if (m14) return Date.UTC(+m14[1],+m14[2]-1,+m14[3],+m14[4],+m14[5],+m14[6]) - KST_OFFSET_MS;
  // 8자리: YYYYMMDD (기업마당 등)
  const m8 = s0.match(/^(\d{4})(\d{2})(\d{2})$/);
  if (m8) return Date.UTC(+m8[1],+m8[2]-1,+m8[3]) - KST_OFFSET_MS;
  const t = Date.parse(s0);
  return Number.isFinite(t) ? t : null;
}

// NocoDB 기존 레코드 맵: 공고ID → NocoDB Id(정수)
const existingMap = new Map();
for (const item of allItems) {
  const j = item.json;
  if (!j || !j._fromNocoDB) continue;
  const fullId = String(j.공고ID || '').trim();
  if (!fullId) continue;
  existingMap.set(fullId, { recordId: j.Id });
}

console.log(`기존 공고 수(NocoDB): ${existingMap.size}`);

function guessSource(j) {
  if (j?.수집출처) return String(j.수집출처);
  const id = String(j?.공고ID || '');
  if (id.startsWith('SUBSIDY24_')) return '보조금24';
  if (id.startsWith('KSTARTUP_')) return 'K-Startup';
  if (id.startsWith('BIZINFO_')) return '기업마당';
  return 'unknown';
}

const seenIds = new Set();
const out = [];
const stats = { inTotal: allItems.length, inAnnouncements: 0, outTotal: 0, bySourceOut: {}, dropped: {} };

for (const item of allItems) {
  const j = item.json;
  if (!j || j._fromNocoDB) continue;

  const fullIdRaw = j.공고ID;
  if (!fullIdRaw || !String(fullIdRaw).trim()) continue;
  stats.inAnnouncements++;

  const fullId = String(fullIdRaw).trim();
  if (seenIds.has(fullId)) { stats.dropped.duplicateInRun = (stats.dropped.duplicateInRun||0)+1; continue; }
  seenIds.add(fullId);

  const title = j.지원사업이름;
  if (!title || !String(title).trim()) continue;

  const source = guessSource(j);
  const isSubsidy24 = source === '보조금24' || fullId.startsWith('SUBSIDY24_');

  const postedRaw = j.게시일시_raw ?? j.수정일시_raw ?? j.등록일시_raw ?? null;
  if (!postedRaw) continue;

  const postedUtcMs = parseToUtcMs(postedRaw);
  if (postedUtcMs === null) continue;

  const startUtcMs = isSubsidy24 ? startUtcMsSubsidy24 : startUtcMsDefault;
  const bypassWindow = FORCE_FULL_SYNC_ALL || (FORCE_FULL_SYNC_SUBSIDY24 && isSubsidy24);
  // 마감일 체크: endDate가 오늘 이후이면 만료되지 않은 공고
  const endDateRaw = j.마감일시_raw ?? j.접수마감일_raw ?? j.endDate ?? null;
  const endDateUtcMs = endDateRaw ? parseToUtcMs(endDateRaw) : null;
  const todayStartUtcMs = Date.UTC(y, m, d, 0, 0, 0) - KST_OFFSET_MS;
  const isNotExpired = endDateUtcMs !== null && endDateUtcMs >= todayStartUtcMs;
  const isRecentPost = !bypassWindow ? (postedUtcMs >= startUtcMs && postedUtcMs <= endUtcMs) : true;

  // 게시일이 14일 이내 OR 마감일이 오늘 이후 → 둘 중 하나면 통과
  if (!isRecentPost && !isNotExpired) continue;

  const existing = existingMap.get(fullId);

  if (!existing) {
    out.push({ json: { ...j, _action: 'create' } });
  } else {
    out.push({ json: { ...j, _action: 'update', _nocodbId: existing.recordId } });
  }

  stats.bySourceOut[source] = (stats.bySourceOut[source] || 0) + 1;
}

stats.outTotal = out.length;
console.log('필터 결과:', stats.outTotal, '/ bySource:', stats.bySourceOut);

if (out.length === 0) {
  return [{ json: { _noNewItems: true, message: '신규/업데이트 공고 없음', debug: stats } }];
}
return out;

// 사전 필터링 v4 - Gemini 배치 최적화: 완전 무관 업종만 제외, 지역 제한 없음
// 목표: 최대한 많은 공고를 Gemini에게 전달하여 AI가 직접 관련성 판단
const items = $input.all();

// 제외 키워드: 업종 자체가 완전히 무관한 경우만 (꽃/공예 도소매와 절대 무관)
const EXCLUDE_INDUSTRIES = ['농업', '어업', '축산', '임업', '광업', '수산업', '어민', '농민', '축산농가', '선박', '조선'];

const filtered = [];
for (const item of items) {
  const d = item.json;
  if (!d.공고ID || !d.지원사업이름) continue;

  // 제목 + 지원대상 + 지원분야 통합 텍스트
  const txt = (
    (d.지원사업이름 || '') + ' ' +
    (d.지원대상 || '') + ' ' +
    (d.지원분야 || '')
  ).toLowerCase();

  // 완전 무관 업종이면 제외
  const isIrrelevant = EXCLUDE_INDUSTRIES.some(kw => txt.includes(kw));
  if (isIrrelevant) continue;

  filtered.push(item);
}

return filtered.length === 0 ? [{ json: { _noItems: true } }] : filtered;

// 배치 프롬프트 생성 - 전체 공고를 단일 Gemini 호출로 분류 (무료 RPM 최적화)
const allItems = $input.all();

// 회사 프로파일 추출 (NocoDB 또는 하드코딩 폴백)
let cp = {
  회사명: 'Pressco21',
  업종: '꽃/공예 도소매',
  소재지: '서울특별시',
  직원수: 8,
  연매출_억원: 3.2,
  주요사업: '꽃 도매, 조화, 공예용품, 온라인몰 운영, 파트너 클래스',
  현재_고민사항: '온라인 채널 확장, 직원 교육 체계화',
};

for (const item of allItems) {
  const j = item.json;
  if (j.list && Array.isArray(j.list) && j.list.length > 0) {
    const p = j.list[0];
    if (p.회사명) { cp = { ...cp, ...p }; break; }
  }
  if (j.회사명 && j.업종) { cp = { ...cp, ...j }; break; }
}

// 공고 아이템 추출
const announcements = allItems.filter(item => item.json.공고ID && item.json.지원사업이름);

if (announcements.length === 0) {
  return [{ json: { _noItems: true } }];
}

// 배치 분류용 경량 배열 (토큰 절약)
const batchList = announcements.map(item => ({
  id: item.json.공고ID,
  제목: item.json.지원사업이름,
  기관: (item.json.소관기관 || '').substring(0, 30),
  대상: (item.json.지원대상 || '').substring(0, 80),
  분야: (item.json.지원분야 || '').substring(0, 50),
  지역: item.json.지역 || '전국',
}));

const systemPrompt = '당신은 정부지원사업 전문 분석가입니다. 반드시 순수 JSON 배열만 반환하고, 마크다운 코드블록 없이 [ 로 시작하여 ] 로 끝나야 합니다.';

const userPrompt = '다음 ' + batchList.length + '개 정부지원사업 공고를 아래 회사 기준으로 관련도 분류하세요.\n\n[회사 정보]\n- 회사명: ' + cp.회사명 + '\n- 업종: ' + cp.업종 + '\n- 소재지: ' + cp.소재지 + '\n- 직원수: ' + cp.직원수 + '명\n- 연매출: ' + cp.연매출_억원 + '억원\n- 주요사업: ' + cp.주요사업 + '\n- 현재고민: ' + (cp.현재_고민사항 || '') + '\n\n[공고 목록]\n' + JSON.stringify(batchList) + '\n\n위 ' + batchList.length + '개 공고 각각에 대해 아래 형식의 JSON 배열만 반환하세요:\n[{"id":"공고ID","점수":정수0~100,"등급":"고관련 또는 검토 또는 저관련","이유":"한줄요약"},...]\n\n점수기준: 고관련=70이상, 검토=30~69, 저관련=0~29\n자격요건 불일치(농업인 전용 등)는 반드시 0~10점 부여.';

return [{
  json: {
    _batchMode: true,
    _batchCount: announcements.length,
    _announcements: announcements.map(i => i.json),
    systemPrompt: systemPrompt,
    userPrompt: userPrompt,
    fullPrompt: systemPrompt + "\n\n" + userPrompt,
  }
}];

// Gemini 배치 응답 파싱 v4 - 상위 30건 선별에서 직접 원본 데이터 조회 후 1→N 확장
const responses = $input.all();

// 원본 공고 데이터: 상위 30건 선별 노드에서 직접 조회
const rawAnnouncements = $('상위 30건 선별').all().map(item => item.json);

function extractText(response) {
  if (!response) return '';
  const j = response.json || response;
  if (j.text) return j.text;
  if (j.candidates?.[0]?.content?.parts?.[0]?.text) return j.candidates[0].content.parts[0].text;
  if (j.content?.parts?.[0]?.text) return j.content.parts[0].text;
  const str = JSON.stringify(j);
  const m = str.match(/"text"\s*:\s*"([\s\S]*?)"/);
  return m ? m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : '';
}

// Gemini 응답에서 텍스트 추출
const firstResponse = responses[0];
const text = extractText(firstResponse);

// JSON 배열 파싱 (코드블록 우선)
let jsonStr = '';
const codeBlockMatch = text.match(/```(?:json)?\s*(\[[\s\S]*?\])\s*```/);
if (codeBlockMatch) {
  jsonStr = codeBlockMatch[1];
} else {
  const arrMatch = text.match(/\[[\s\S]*\]/);
  if (arrMatch) jsonStr = arrMatch[0];
}

if (!jsonStr || rawAnnouncements.length === 0) {
  return rawAnnouncements.map(ann => ({
    json: { ...ann, 관련도점수: 0, 관련도등급: '저관련', 관련도이유: 'Gemini 응답 파싱 실패' }
  }));
}

let batchScores;
try {
  batchScores = JSON.parse(jsonStr);
} catch (e) {
  return rawAnnouncements.map(ann => ({
    json: { ...ann, 관련도점수: 0, 관련도등급: '저관련', 관련도이유: 'JSON 파싱 오류: ' + e.message }
  }));
}

// scoreMap 생성 (공고ID → 점수 데이터)
const scoreMap = {};
for (const item of batchScores) {
  scoreMap[String(item.id)] = item;
}

// 원본 공고 데이터에 점수 병합하여 반환
return rawAnnouncements.map(ann => {
  const sd = scoreMap[String(ann.공고ID)] || {};
  const score = Number(sd.점수 ?? 0);
  const grade = score >= 70 ? '고관련' : score >= 30 ? '검토' : '저관련';
  return {
    json: {
      ...ann,
      관련도점수: score,
      관련도등급: grade,
      관련도이유: sd.이유 || '',
    }
  };
});

const items = $input.all();
if (items.length > 0) return [];
const today = new Date().toLocaleDateString('ko-KR', { timeZone: 'Asia/Seoul', year: 'numeric', month: '2-digit', day: '2-digit' });
return [{ json: { isEmpty: true, 수집일: today } }];

